// Generated by Claude Opus 4.6

import { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';

import { baseApiPath } from '@/constants/config';
import { namespacedSchema } from '@/constants/schemas';
import {
  JSON_MERGE_PATCH_OPTIONS,
  STRATEGIC_MERGE_PATCH_OPTIONS,
} from '@/devworkspaceClient/services/helpers/patchOptions';
import { restParams } from '@/models';
import {
  CONFIGMAP_NAME,
  DevfileIdParams,
  generateDevfileId,
  getCoreV1Api,
  getOrCreateConfigMap,
  MODIFIED_ANNOTATION_PREFIX,
  parseEntries,
} from '@/routes/api/helpers/devfile';
import { getToken } from '@/routes/api/helpers/getToken';
import { getSchema } from '@/services/helpers';

const tags = ['Devfiles'];

const namespacedIdSchema = {
  type: 'object',
  required: ['namespace', 'id'],
  properties: {
    namespace: { type: 'string', description: 'Kubernetes namespace of the user' },
    id: { type: 'string', description: 'UUID of the devfile entry in the ConfigMap' },
  },
};

const MAX_DEVFILE_CONTENT_SIZE = 524288; // 512 KiB

const devfileContentBodySchema = {
  type: 'object',
  required: ['content'],
  properties: {
    content: {
      type: 'string',
      minLength: 1,
      maxLength: MAX_DEVFILE_CONTENT_SIZE,
      description: 'YAML content of the devfile (max 512 KiB)',
    },
  },
  additionalProperties: false,
};

export function registerDevfilesRoute(instance: FastifyInstance) {
  instance.register(async server => {
    // List all devfiles
    server.get(
      `${baseApiPath}/devfiles/namespace/:namespace`,
      getSchema({
        tags,
        summary: 'List all devfiles',
        description:
          'Returns all devfile entries stored in the devfile-creator-storage ConfigMap ' +
          'in the given namespace. Each entry includes parsed metadata (name, description, ' +
          'project count) and the raw YAML content.',
        params: namespacedSchema,
      }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        return { devfiles: parseEntries(configMap.data, configMap.metadata?.annotations) };
      },
    );

    // Create new devfile
    server.post(
      `${baseApiPath}/devfiles/namespace/:namespace`,
      getSchema({
        tags,
        summary: 'Create a new devfile',
        description:
          'Stores a new devfile YAML entry in the devfile-creator-storage ConfigMap. ' +
          'Assigns a random UUID as the entry key and records a last-modified annotation.',
        params: namespacedSchema,
        body: devfileContentBodySchema,
      }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const body = request.body as { content: string };
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const id = generateDevfileId(body.content);
        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        const data = { ...configMap.data, [id]: body.content };
        const now = new Date().toISOString();

        await coreV1Api.patchNamespacedConfigMap(
          {
            name: CONFIGMAP_NAME,
            namespace,
            body: {
              metadata: {
                annotations: { [`${MODIFIED_ANNOTATION_PREFIX}${id}`]: now },
              },
              data,
            },
          },
          STRATEGIC_MERGE_PATCH_OPTIONS,
        );

        return { id };
      },
    );

    // Update devfile
    server.put(
      `${baseApiPath}/devfiles/namespace/:namespace/:id`,
      getSchema({
        tags,
        summary: 'Update an existing devfile',
        description:
          'Replaces the YAML content of an existing devfile entry identified by its UUID. ' +
          'Returns 404 if the entry does not exist.',
        params: namespacedIdSchema,
        body: devfileContentBodySchema,
      }),
      async function (request: FastifyRequest) {
        const { namespace, id } = request.params as DevfileIdParams;
        const body = request.body as { content: string };
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        if (!configMap.data?.[id]) {
          throw new Error(`Devfile with id "${id}" not found`);
        }

        const data: Record<string, string | null> = { ...configMap.data, [id]: body.content };
        const annotations: Record<string, string | null> = {};
        const now = new Date().toISOString();
        annotations[`${MODIFIED_ANNOTATION_PREFIX}${id}`] = now;

        await coreV1Api.patchNamespacedConfigMap(
          {
            name: CONFIGMAP_NAME,
            namespace,
            body: { metadata: { annotations }, data },
          },
          JSON_MERGE_PATCH_OPTIONS,
        );

        return { id };
      },
    );

    // Delete devfile
    server.delete(
      `${baseApiPath}/devfiles/namespace/:namespace/:id`,
      getSchema({
        tags,
        summary: 'Delete a devfile',
        description:
          'Removes a devfile entry from the devfile-creator-storage ConfigMap using ' +
          'a JSON merge patch (sets the key to null). Returns 204 on success.',
        params: namespacedIdSchema,
      }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace, id } = request.params as DevfileIdParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        if (configMap.data?.[id]) {
          await coreV1Api.patchNamespacedConfigMap(
            {
              name: CONFIGMAP_NAME,
              namespace,
              body: { data: { [id]: null } },
            },
            JSON_MERGE_PATCH_OPTIONS,
          );
        }

        reply.code(204).send();
      },
    );

    // Raw devfile content
    server.get(
      `${baseApiPath}/devfiles/namespace/:namespace/:id/raw`,
      getSchema({
        tags,
        summary: 'Get raw devfile YAML',
        description:
          'Returns the raw YAML content of a devfile entry as text/yaml. ' +
          'Used by the factory flow to create workspaces from stored devfiles.',
        params: namespacedIdSchema,
      }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace, id } = request.params as DevfileIdParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        const content = configMap.data?.[id];
        if (!content) {
          return reply.status(404).send('Devfile not found');
        }

        reply.header('Content-Type', 'text/yaml; charset=utf-8');
        return reply.send(content);
      },
    );
  });
}
